insert into public.knowledge_entries
  (type, title, body, category, tags, source_type, source_id, source_title, status, confidence, created_by)
values
('term','보험증권','보험계약의 성립과 그 내용을 증명하기 위하여 보험회사가 계약자에게 교부하는 증서. 보장 내용, 보험료, 보험기간 등 계약의 주요 사항이 기재된다. 상법 제640조에 근거한다.','계약',array['보험증권','증서','계약성립','교부'],'cycle1_mined','cycle1_mined','상법 제640조 (국가법령정보센터)','ai_draft','high','admin'),
('term','중복보험','동일한 피보험자가 같은 위험을 보장하는 복수의 보험계약에 가입하여 보험금액의 총액이 보험가액을 초과하는 경우. 손해보험에 적용되는 개념으로, 상법 제672조에 따라 각 보험자는 자신의 보험금액 한도 내에서 연대하여 보상 책임을 진다.','계약',array['중복보험','보험금액','보험가액','손해보험'],'cycle1_mined','cycle1_mined','상법 제672조 (국가법령정보센터)','ai_draft','high','admin'),
('term','보험가액','손해보험에서 사고 발생 시 피보험자가 입게 되는 손해의 최대 한도를 금전으로 평가한 금액. 상법 제670조(기평가보험)와 제671조(미평가보험)에 따라 계약 당사자 간 합의 또는 사고 당시 가액을 기준으로 산정한다. 생명보험에는 적용되지 않는 손해보험 고유 개념이다.','계약',array['보험가액','손해보험','피보험이익','평가'],'cycle1_mined','cycle1_mined','상법 제670조·제671조 (국가법령정보센터)','ai_draft','high','admin'),
('term','납입최고','보험료 납입 기한을 지키지 않은 계약자에게 보험회사가 상당한 기간을 정하여 연체 보험료의 납입을 서면으로 독촉하는 행위. 상법 제650조 제2항에 따라 최고 기간이 종료될 때까지 보험료가 납입되지 않으면 보험회사는 계약을 해지할 수 있다.','계약',array['납입최고','연체','독촉','계약해지'],'cycle1_mined','cycle1_mined','상법 제650조 (국가법령정보센터)','ai_draft','high','admin'),
('term','책임개시일','보험계약 체결 후 보험자가 보험사고에 대한 보상 책임을 실제로 지기 시작하는 날. 상법 제656조에 따라 별도 약정이 없으면 최초 보험료를 수령한 시점부터 보험자의 책임이 개시되며, 약관으로 달리 정할 수 있다.','계약',array['책임개시일','최초보험료','보험자책임','상법656조'],'cycle1_mined','cycle1_mined','찾기쉬운 생활법령정보 — 보험계약의 체결 및 책임개시시기 (easylaw.go.kr) + 상법 제656조','ai_draft','high','admin'),
('term','고지의무위반 계약해지','보험계약 체결 당시 계약자 또는 피보험자가 고의 또는 중대한 과실로 중요한 사항을 고지하지 않거나 사실과 다르게 고지한 경우, 보험자가 그 사실을 안 날부터 약관에서 정한 기간 이내 또는 계약 체결일부터 일정 기간 이내에 계약을 해지할 수 있는 제도. 상법 제651조에 규정되어 있다.','계약',array['고지의무위반','계약해지','상법651조','중요사항'],'cycle1_mined','cycle1_mined','상법 제651조 (국가법령정보센터) + 찾기쉬운 생활법령정보','ai_draft','high','admin'),
('term','특약','기본 보험계약(주계약)에 추가로 부가하여 보장 범위를 확대하거나 변경하는 선택적 보험 계약으로, 주계약 없이 단독으로 존재할 수 없다.','보장',array['특약','주계약 부가','추가 보장','선택'],'cycle1_mined','cycle1_mined','금융감독원 보험용어 (fss.or.kr) · 찾기쉬운 생활법령정보 (easylaw.go.kr)','ai_draft','high','admin'),
('term','청약서','보험계약 체결을 신청할 때 청약자가 작성하는 문서. 개인 정보·건강 상태·병력·직업 등 인수심사에 필요한 사항을 기재하며, 고지의무 이행의 기본 수단이 된다.','인수',array['청약서','가입신청서','고지서류','계약청약'],'cycle1_mined','cycle1_mined','법제처 찾기 쉬운 생활법령정보 (easylaw.go.kr) / 금융감독원 파인 (fine.fss.or.kr)','ai_draft','high','admin'),
('term','계약변경','보험계약 유지 중 계약자의 신청에 따라 약관에서 정한 절차에 따라 계약 내용(보험금액, 납입기간, 특약 구성 등)을 변경하는 행위. 표준약관 「계약내용의 변경」 조항에 근거하며, 변경 시 보험회사의 승인이 필요하다.','계약',array['계약변경','계약내용변경','표준약관','보험금액변경'],'cycle1_mined','cycle1_mined','생명보험 표준약관 「계약내용의 변경」','ai_draft','medium','admin'),
('term','보험금청구','보험계약자, 피보험자 또는 수익자가 보험사고 발생 후 약관에 근거하여 보험회사에 보험금을 청구하는 행위. 상법 제662조에 따라 보험금청구권은 약관에서 정한 기간(통상 3년) 내에 행사하지 않으면 시효로 소멸한다.','민원',array['보험금청구','청구절차','소멸시효','상법662조'],'cycle1_mined','cycle1_mined','상법 제662조 (국가법령정보센터) + 금융감독원 파인','ai_draft','medium','admin'),
('term','지정대리청구서비스특약','치매나 중증 질환 등으로 보험수익자가 보험금을 직접 청구하기 어려운 상황에 대비하여, 계약자가 사전에 배우자 또는 약관에서 정한 범위 내 친족을 대리청구인으로 지정해 두는 특약. 지정된 대리인은 수익자를 대신하여 보험금을 청구할 수 있다.','계약',array['지정대리청구','대리청구인','보험금청구','치매대비'],'cycle1_mined','cycle1_mined','금융감독원 파인 (fine.fss.or.kr)','ai_draft','medium','admin'),
('term','담보','보험 약관에서 보험회사가 보험금을 지급하기로 약정한 보험사고 항목으로, 보험계약의 보장 범위를 구성하는 단위를 말한다.','보장',array['담보','보험사고','보험금 지급','약관'],'cycle1_mined','cycle1_mined','금융감독원 보험용어 (fss.or.kr)','ai_draft','medium','admin'),
('term','실손의료비','피보험자가 질병이나 상해로 인해 의료기관에서 실제로 부담한 의료비를 보상하는 보장으로, 입원·외래·처방조제비 항목에 걸쳐 실제 지출 비용을 보전한다.','보장',array['실손의료비','실제 부담 의료비','입원','통원'],'cycle1_mined','cycle1_mined','손해보험협회 실손의료보험 안내 (kpub.knia.or.kr · consumer.knia.or.kr)','ai_draft','high','admin'),
('term','통원비','의료기관에 입원하지 않고 외래로 방문하여 진료를 받을 때 발생하는 의료비를 보상하는 보장으로, 실손의료보험 내 통원의료비 항목에 해당한다. 독립 보험 상품 개념과 혼동하지 않도록 주의가 필요하다.','보장',array['통원비','외래진료','통원의료비','실손보험'],'cycle1_mined','cycle1_mined','손해보험협회 실손의료보험 안내 (kpub.knia.or.kr)','ai_draft','medium','admin'),
('term','주계약','보험계약의 기본이 되는 핵심 계약으로, 특약은 이 주계약에 부가되는 형태로만 성립된다. 보험료·보험금·보장 범위의 기준이 된다.','보장',array['주계약','기본 보험','특약 기준','핵심 보장'],'cycle1_mined','cycle1_mined','금융감독원 보험용어 (fss.or.kr)','ai_draft','medium','admin'),
('term','갱신형','정해진 갱신 주기(1년·3년·5년·10년 등)가 도래할 때마다 보험료를 재계산하고 계약을 갱신하는 보험 형태로, 갱신 시 연령 및 위험률 변화가 보험료에 반영된다.','보장',array['갱신형','보험료 재계산','갱신 주기','연령 적용'],'cycle1_mined','cycle1_mined','금융감독원 보험상품 안내 (fine.fss.or.kr/main/prc/is/sub/is015.jsp · is003.jsp)','ai_draft','high','admin'),
('term','비갱신형','보험 계약 기간 동안 보험료가 고정되어 재계산 없이 계약 종료 시까지 같은 금액을 납입하는 보험 형태로, 갱신형과 대비되는 개념이다.','보장',array['비갱신형','고정 보험료','갱신형 대비','장기 고정'],'cycle1_mined','cycle1_mined','금융감독원 보험상품 안내 (fine.fss.or.kr/main/prc/is/sub/is015.jsp)','ai_draft','medium','admin'),
('term','보장개시일','보험계약에서 보험회사의 보장 책임이 시작되는 날짜로, 이 날부터 보험사고가 발생할 때 약관에 따라 보험금을 지급한다.','보장',array['보장개시일','책임 시작일','효력 발생','보험사고 기준'],'cycle1_mined','cycle1_mined','금융감독원 보험용어 (fss.or.kr)','ai_draft','medium','admin'),
('term','무배당','보험회사가 보험료 운용 차익을 계약자에게 배당금으로 돌려주지 않는 상품 형태로, 배당보험에 비해 상대적으로 보험료가 저렴하게 설계된다.','제도',array['무배당','배당금 미지급','상품 형태','보험료'],'cycle1_mined','cycle1_mined','금융감독원 보험용어 (fss.or.kr)','ai_draft','medium','admin'),
('term','배상책임보험','개인의 일상생활이나 기업의 영업활동 중 발생한 사고로 타인의 신체나 재산에 피해를 입혔을 때 법률상 배상 책임을 보상하는 보험이다.','상품',array['배상책임보험','법률상 책임','타인 피해','제3자 보험'],'cycle1_mined','cycle1_mined','손해보험협회 교육센터 (edu.knia.or.kr) · 손해보험협회 소비자포털 (consumer.knia.or.kr)','ai_draft','high','admin'),
('term','장해등급','상해나 질병으로 인한 신체 장해의 정도를 등급별로 분류한 기준으로, 보험업감독업무시행세칙 별표(장해분류표)에 근거하여 장해율을 산정한다.','보장',array['장해등급','장해분류표','장해율','신체 손상'],'cycle1_mined','cycle1_mined','보험업감독업무시행세칙 별표 (장해분류표) (law.go.kr)','ai_draft','medium','admin'),
('term','갱신보험료','갱신형 보험의 갱신 시점에 피보험자의 연령 증가와 위험률 변화를 반영하여 재계산된 보험료를 말한다.','보장',array['갱신보험료','갱신 시점','재계산','위험률'],'cycle1_mined','cycle1_mined','금융감독원 보험상품 안내 (fine.fss.or.kr/main/prc/is/sub/is015.jsp)','ai_draft','medium','admin'),
('term','비급여','국민건강보험법 제41조 제3항에 따라 건강보험 요양급여 대상에서 제외되어 환자가 전액 부담하는 의료 항목을 말한다. 실손의료보험에서 주요 보장 대상이 된다.','보장',array['비급여','환자 전액 부담','요양급여 제외','실손보험 대상'],'cycle1_mined','cycle1_mined','건강보험심사평가원 HIRA (hira.or.kr)','ai_draft','high','admin'),
('term','암진단비','암으로 진단받았을 때 치료비 부담을 경감하기 위해 지급되는 보험금으로, 약관에서 정한 암의 종류 및 진단 기준에 따라 지급 여부와 금액이 결정된다.','보장',array['암진단비','암 진단금','중대질병','진단급부'],'cycle1_mined','cycle1_mined','금융감독원 보험용어 (fss.or.kr) · 손해보험협회 장기보험 안내 (kpub.knia.or.kr)','ai_draft','medium','admin'),
('term','급성심근경색진단비','급성심근경색증으로 진단받았을 때 지급되는 보험금으로, 약관에서 정한 진단 기준에 따라 지급 여부와 금액이 결정된다. ''3대 질병'' 포함 여부는 상품별 약관을 확인해야 한다.','보장',array['급성심근경색진단비','심근경색','심장질환','진단급부'],'cycle1_mined','cycle1_mined','손해보험협회 장기보험 안내 (kpub.knia.or.kr)','ai_draft','medium','admin'),
('term','만기환급금','보험기간이 만료되었을 때 약관에 따라 계약자에게 지급되는 환급금으로, 납입한 보험료 및 운용 이익에 따라 금액이 결정된다.','제도',array['만기환급금','만기 환급','계약 종료','보험료 반환'],'cycle1_mined','cycle1_mined','금융감독원 보험용어 (fine.fss.or.kr)','ai_draft','medium','admin'),
('term','자기부담금','보험사고 발생 시 피보험자가 보험금 청구 전 직접 부담하는 일정 금액 또는 비율로, 실손의료보험에서는 보장대상 의료비의 일정 비율을 가입자가 부담하도록 설계된 장치다. 적용 비율은 세대별·약관에 따라 상이하다.','보장',array['자기부담금','자기부담률','공제금액','실손보험'],'cycle1_mined','cycle1_mined','손해보험협회 실손의료보험 안내 (kpub.knia.or.kr)','ai_draft','medium','admin'),
